/**
 * 01 - Build Error Log File
 *
 * Purpose:
 * - Receives error details from n8n Error Trigger.
 * - Builds a clean JSON error log.
 * - Converts it to binary so the next node can write it to disk.
 *
 * Portfolio version:
 * - Generic B2B lead pipeline wording
 * - No client, company, or assessment-specific naming
 */

function safe(value, fallback = "") {
  if (value === null || value === undefined || value === "") return fallback;
  return value;
}

function cleanFileTimestamp() {
  return new Date()
    .toISOString()
    .replace(/[:.]/g, "-");
}

const errorEvent = items[0]?.json || {};

const workflow = errorEvent.workflow || {};
const execution = errorEvent.execution || {};
const node = errorEvent.node || {};
const topLevelError = errorEvent.error || {};
const executionError = execution.error || {};

const timestamp = new Date().toISOString();
const fileTimestamp = cleanFileTimestamp();

const failedNodeName =
  safe(node.name, "") ||
  safe(execution.lastNodeExecuted, "unknown");

const failedNodeType =
  safe(node.type, "unknown");

const errorName =
  safe(topLevelError.name, "") ||
  safe(executionError.name, "unknown");

const errorMessage =
  safe(topLevelError.message, "") ||
  safe(executionError.message, "unknown");

const errorStack =
  safe(topLevelError.stack, "") ||
  safe(executionError.stack, "");

const errorLog = {
  file_type: "lead_pipeline_error_log",
  generated_at: timestamp,

  workflow: {
    id: safe(workflow.id, "unknown"),
    name: safe(workflow.name, "unknown")
  },

  execution: {
    id: safe(execution.id, "unknown"),
    mode: safe(execution.mode, "unknown"),
    url: safe(execution.url, ""),
    retry_of: safe(execution.retryOf, "")
  },

  failed_node: {
    name: failedNodeName,
    type: failedNodeType
  },

  error: {
    name: errorName,
    message: errorMessage,
    stack: errorStack
  },

  raw_error_event: errorEvent
};

const fileName = `lead_pipeline_error_log_${fileTimestamp}.json`;
const filePath = `/home/node/.n8n-files/error_logs/${fileName}`;
const fileContent = JSON.stringify(errorLog, null, 2);

return [
  {
    json: {
      file_name: fileName,
      file_path: filePath,
      generated_at: timestamp,
      error_workflow_status: "prepared",
      workflow_name: errorLog.workflow.name,
      failed_node_name: errorLog.failed_node.name,
      error_message: errorLog.error.message
    },
    binary: {
      data: {
        data: Buffer.from(fileContent, "utf8").toString("base64"),
        mimeType: "application/json",
        fileName
      }
    }
  }
];
